import json
import time
import uuid
from collections import defaultdict

class Event:
    def __init__(self, event_type, aggregate_id, data):
        self.id = str(uuid.uuid4())[:8]
        self.event_type = event_type
        self.aggregate_id = aggregate_id
        self.data = data
        self.timestamp = time.time()
    def to_dict(self):
        return {'id': self.id, 'type': self.event_type, 'aggregate_id': self.aggregate_id, 'data': self.data, 'ts': self.timestamp}

class EventStore:
    def __init__(self):
        self.events = []
        self.projections = {}
    def append(self, event):
        self.events.append(event)
        self._notify_projections(event)
        return event
    def get_events(self, aggregate_id=None):
        if aggregate_id:
            return [e for e in self.events if e.aggregate_id == aggregate_id]
        return list(self.events)
    def register_projection(self, name, handler):
        self.projections[name] = {'handler': handler, 'state': {}}
    def _notify_projections(self, event):
        for name, proj in self.projections.items():
            proj['handler'](proj['state'], event)
    def replay(self, projection_name):
        proj = self.projections[projection_name]
        proj['state'] = {}
        for event in self.events:
            proj['handler'](proj['state'], event)
        return proj['state']
    def get_projection(self, name):
        return self.projections[name]['state']

# Demo: Bank account event sourcing
store = EventStore()

def balance_projection(state, event):
    aid = event.aggregate_id
    if aid not in state:
        state[aid] = 0
    if event.event_type == 'deposited':
        state[aid] += event.data['amount']
    elif event.event_type == 'withdrawn':
        state[aid] -= event.data['amount']

def tx_count_projection(state, event):
    aid = event.aggregate_id
    if aid not in state:
        state[aid] = 0
    state[aid] += 1

store.register_projection('balances', balance_projection)
store.register_projection('tx_counts', tx_count_projection)

store.append(Event('deposited', 'acc-001', {'amount': 1000}))
store.append(Event('deposited', 'acc-001', {'amount': 500}))
store.append(Event('withdrawn', 'acc-001', {'amount': 200}))
store.append(Event('deposited', 'acc-002', {'amount': 300}))

print(f'Events: {len(store.events)}')
print(f'Balances: {store.get_projection("balances")}')
print(f'TX counts: {store.get_projection("tx_counts")}')

# Replay from scratch
replay_state = store.replay('balances')
print(f'Replayed balances: {replay_state}')
print(f'Event log:')
for e in store.get_events('acc-001'):
    print(f'  {e.event_type}: {e.data}')

