import os
import importlib.util
import inspect
from pathlib import Path

class PluginRegistry:
    def __init__(self):
        self.plugins = {}
        self.hooks = {}
    def register(self, name, plugin_class):
        instance = plugin_class()
        self.plugins[name] = instance
        # Auto-discover hooks
        for method_name in dir(instance):
            if method_name.startswith('on_'):
                hook_name = method_name[3:]
                if hook_name not in self.hooks:
                    self.hooks[hook_name] = []
                self.hooks[hook_name].append(instance)
        print(f'[PLUGIN] Registered: {name} (hooks: {[m[3:] for m in dir(instance) if m.startswith("on_")]})')
    def discover(self, plugin_dir):
        plugin_path = Path(plugin_dir)
        if not plugin_path.exists():
            return []
        loaded = []
        for f in plugin_path.glob('*.py'):
            if f.name.startswith('_'):
                continue
            spec = importlib.util.spec_from_file_location(f.stem, f)
            module = importlib.util.module_from_spec(spec)
            try:
                spec.loader.exec_module(module)
                for name, obj in inspect.getmembers(module, inspect.isclass):
                    if hasattr(obj, 'plugin_name'):
                        self.register(obj.plugin_name, obj)
                        loaded.append(obj.plugin_name)
            except Exception as e:
                print(f'[PLUGIN] Failed to load {f.name}: {e}')
        return loaded
    def trigger(self, hook_name, *args, **kwargs):
        results = []
        for plugin in self.hooks.get(hook_name, []):
            method = getattr(plugin, f'on_{hook_name}')
            try:
                result = method(*args, **kwargs)
                results.append(result)
            except Exception as e:
                print(f'[PLUGIN] Hook error in {plugin.__class__.__name__}.on_{hook_name}: {e}')
        return results
    def get_plugin(self, name):
        return self.plugins.get(name)
    def list_plugins(self):
        return list(self.plugins.keys())
    def list_hooks(self):
        return {k: [p.__class__.__name__ for p in v] for k, v in self.hooks.items()}

# Demo with inline plugins
class LoggingPlugin:
    plugin_name = 'logger'
    def on_request(self, data): print(f'  [LOG] Request: {data}'); return 'logged'
    def on_error(self, error): print(f'  [LOG] Error: {error}')

class MetricsPlugin:
    plugin_name = 'metrics'
    counter = 0
    def on_request(self, data): MetricsPlugin.counter += 1; print(f'  [METRIC] Request #{MetricsPlugin.counter}'); return MetricsPlugin.counter
    def on_shutdown(self): print(f'  [METRIC] Total requests: {MetricsPlugin.counter}')

registry = PluginRegistry()
registry.register('logger', LoggingPlugin)
registry.register('metrics', MetricsPlugin)

print(f'\nPlugins: {registry.list_plugins()}')
print(f'Hooks: {registry.list_hooks()}')

print('\nTriggering request hook:')
results = registry.trigger('request', {'path': '/api/users', 'method': 'GET'})
print(f'Hook results: {results}')

print('\nTriggering error hook:')
registry.trigger('error', 'Connection timeout')

print('\nTriggering shutdown hook:')
registry.trigger('shutdown')

