import time
import threading
from collections import deque
from functools import wraps

class TokenBucket:
    def __init__(self, rate, capacity):
        self.rate = rate
        self.capacity = capacity
        self.tokens = capacity
        self.last_refill = time.time()
        self.lock = threading.Lock()
    def consume(self, tokens=1):
        with self.lock:
            now = time.time()
            elapsed = now - self.last_refill
            self.tokens = min(self.capacity, self.tokens + elapsed * self.rate)
            self.last_refill = now
            if self.tokens >= tokens:
                self.tokens -= tokens
                return True
            return False

class SlidingWindowLimiter:
    def __init__(self, max_calls, window_seconds):
        self.max_calls = max_calls
        self.window = window_seconds
        self.calls = deque()
        self.lock = threading.Lock()
    def allow(self):
        with self.lock:
            now = time.time()
            while self.calls and self.calls[0] <= now - self.window:
                self.calls.popleft()
            if len(self.calls) < self.max_calls:
                self.calls.append(now)
                return True
            return False
    def remaining(self):
        with self.lock:
            now = time.time()
            while self.calls and self.calls[0] <= now - self.window:
                self.calls.popleft()
            return self.max_calls - len(self.calls)

def rate_limit(max_calls=10, window=60, strategy='sliding'):
    limiter = SlidingWindowLimiter(max_calls, window) if strategy == 'sliding' else TokenBucket(max_calls / window, max_calls)
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            allowed = limiter.allow() if strategy == 'sliding' else limiter.consume()
            if not allowed:
                raise Exception(f'Rate limit exceeded: {max_calls} calls per {window}s')
            return func(*args, **kwargs)
        wrapper.limiter = limiter
        return wrapper
    return decorator

# Demo
@rate_limit(max_calls=5, window=2, strategy='sliding')
def api_call(endpoint):
    return f'Response from {endpoint}'

print('Rate Limiter Demo (5 calls per 2 seconds):')
for i in range(8):
    try:
        result = api_call(f'/api/item/{i}')
        remaining = api_call.limiter.remaining()
        print(f'  Call {i+1}: {result} (remaining: {remaining})')
    except Exception as e:
        print(f'  Call {i+1}: BLOCKED - {e}')
    time.sleep(0.3)
print('Rate limiter demo complete')

