import time
import random
from functools import wraps

class RetryError(Exception):
    def __init__(self, message, attempts, last_error):
        super().__init__(message)
        self.attempts = attempts
        self.last_error = last_error

def retry(max_retries=3, base_delay=1.0, max_delay=60.0, exponential=True, jitter=True, retryable_exceptions=(Exception,)):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            last_exception = None
            for attempt in range(1, max_retries + 1):
                try:
                    return func(*args, **kwargs)
                except retryable_exceptions as e:
                    last_exception = e
                    if attempt == max_retries:
                        raise RetryError(f'Failed after {max_retries} attempts: {e}', attempt, e)
                    if exponential:
                        delay = min(base_delay * (2 ** (attempt - 1)), max_delay)
                    else:
                        delay = base_delay
                    if jitter:
                        delay *= (0.5 + random.random())
                    print(f'  Attempt {attempt}/{max_retries} failed: {e}. Retrying in {delay:.2f}s...')
                    time.sleep(delay)
        return wrapper
    return decorator

# Demo
call_count = 0
@retry(max_retries=5, base_delay=0.1, exponential=True, jitter=True, retryable_exceptions=(ConnectionError, TimeoutError))
def fetch_data(url):
    global call_count
    call_count += 1
    if call_count < 4:
        raise ConnectionError(f'Connection refused (attempt {call_count})')
    return f'Data from {url}'

print('Retry with Exponential Backoff Demo:')
try:
    result = fetch_data('https://api.example.com/data')
    print(f'Success: {result}')
except RetryError as e:
    print(f'All retries exhausted: {e}')

call_count = 0
print('\nTest with permanent failure:')
@retry(max_retries=3, base_delay=0.05, retryable_exceptions=(ValueError,))
def always_fails():
    raise ValueError('Permanent error')

try:
    always_fails()
except RetryError as e:
    print(f'Caught RetryError: {e.attempts} attempts, last error: {e.last_error}')
print('Retry demo complete')

