from enum import Enum, auto
from collections import defaultdict

class StateMachine:
    def __init__(self, initial_state):
        self.state = initial_state
        self.transitions = {}
        self.guards = {}
        self.actions = defaultdict(list)
        self.on_enter = {}
        self.on_exit = {}
        self.history = [initial_state]
    def add_transition(self, from_state, event, to_state, guard=None, action=None):
        key = (from_state, event)
        self.transitions[key] = to_state
        if guard:
            self.guards[key] = guard
        if action:
            self.actions[key].append(action)
    def add_on_enter(self, state, callback):
        self.on_enter[state] = callback
    def add_on_exit(self, state, callback):
        self.on_exit[state] = callback
    def trigger(self, event, **context):
        key = (self.state, event)
        if key not in self.transitions:
            raise ValueError(f'No transition from {self.state} on event {event}')
        guard = self.guards.get(key)
        if guard and not guard(**context):
            print(f'  Guard blocked: {self.state} --{event}--> (blocked)')
            return False
        old_state = self.state
        new_state = self.transitions[key]
        if old_state in self.on_exit:
            self.on_exit[old_state](old_state, event)
        for action in self.actions.get(key, []):
            action(old_state, event, new_state, **context)
        self.state = new_state
        self.history.append(new_state)
        if new_state in self.on_enter:
            self.on_enter[new_state](new_state, event)
        print(f'  Transition: {old_state} --{event}--> {new_state}')
        return True
    def can_trigger(self, event):
        return (self.state, event) in self.transitions
    def get_history(self):
        return list(self.history)

# Demo: Order processing state machine
class OrderState(Enum):
    PENDING = auto()
    CONFIRMED = auto()
    SHIPPED = auto()
    DELIVERED = auto()
    CANCELLED = auto()

sm = StateMachine(OrderState.PENDING)
sm.add_transition(OrderState.PENDING, 'confirm', OrderState.CONFIRMED,
    guard=lambda **ctx: ctx.get('payment_ok', False),
    action=lambda old, evt, new, **ctx: print(f'    Action: sending confirmation email'))
sm.add_transition(OrderState.CONFIRMED, 'ship', OrderState.SHIPPED,
    action=lambda old, evt, new, **ctx: print(f'    Action: generating tracking number'))
sm.add_transition(OrderState.SHIPPED, 'deliver', OrderState.DELIVERED)
sm.add_transition(OrderState.PENDING, 'cancel', OrderState.CANCELLED)
sm.add_transition(OrderState.CONFIRMED, 'cancel', OrderState.CANCELLED)
sm.add_on_enter(OrderState.DELIVERED, lambda s, e: print(f'    Entered DELIVERED state'))

print('Order State Machine Demo:')
sm.trigger('confirm', payment_ok=False)
sm.trigger('confirm', payment_ok=True)
sm.trigger('ship')
sm.trigger('deliver')
print(f'\nFinal state: {sm.state}')
print(f'History: {[s.name for s in sm.get_history()]}')

