from abc import ABC, abstractmethod
from typing import List

class Command(ABC):
    @abstractmethod
    def execute(self): pass
    @abstractmethod
    def undo(self): pass
    @abstractmethod
    def description(self) -> str: pass

class CommandHistory:
    def __init__(self):
        self.undo_stack: List[Command] = []
        self.redo_stack: List[Command] = []
    def execute(self, command):
        command.execute()
        self.undo_stack.append(command)
        self.redo_stack.clear()
        print(f'  Executed: {command.description()}')
    def undo(self):
        if not self.undo_stack:
            print('  Nothing to undo')
            return
        cmd = self.undo_stack.pop()
        cmd.undo()
        self.redo_stack.append(cmd)
        print(f'  Undone: {cmd.description()}')
    def redo(self):
        if not self.redo_stack:
            print('  Nothing to redo')
            return
        cmd = self.redo_stack.pop()
        cmd.execute()
        self.undo_stack.append(cmd)
        print(f'  Redone: {cmd.description()}')
    def history(self):
        return [cmd.description() for cmd in self.undo_stack]

# Demo: Text editor commands
class TextDocument:
    def __init__(self):
        self.content = ''
    def __repr__(self):
        return f'Document("{self.content}")'   

class InsertCommand(Command):
    def __init__(self, doc, text, position=None):
        self.doc = doc
        self.text = text
        self.position = position if position is not None else len(doc.content)
    def execute(self):
        self.doc.content = self.doc.content[:self.position] + self.text + self.doc.content[self.position:]
    def undo(self):
        self.doc.content = self.doc.content[:self.position] + self.doc.content[self.position + len(self.text):]
    def description(self):
        return f'Insert "{self.text}" at {self.position}'

class DeleteCommand(Command):
    def __init__(self, doc, start, end):
        self.doc = doc
        self.start = start
        self.end = end
        self.deleted_text = ''
    def execute(self):
        self.deleted_text = self.doc.content[self.start:self.end]
        self.doc.content = self.doc.content[:self.start] + self.doc.content[self.end:]
    def undo(self):
        self.doc.content = self.doc.content[:self.start] + self.deleted_text + self.doc.content[self.start:]
    def description(self):
        return f'Delete [{self.start}:{self.end}] "{self.deleted_text}"'

doc = TextDocument()
hist = CommandHistory()

print('Command Pattern with Undo/Redo Demo:')
hist.execute(InsertCommand(doc, 'Hello '))
hist.execute(InsertCommand(doc, 'World'))
print(f'  State: {doc}')
hist.execute(DeleteCommand(doc, 5, 11))
print(f'  State: {doc}')
hist.undo()
print(f'  State: {doc}')
hist.undo()
print(f'  State: {doc}')
hist.redo()
print(f'  State: {doc}')
print(f'\nHistory: {hist.history()}')

