from typing import Callable, Any, Dict
import time
import json

class Context:
    def __init__(self, request):
        self.request = request
        self.response = None
        self.metadata = {}
        self.aborted = False
    def abort(self, status, message):
        self.aborted = True
        self.response = {'status': status, 'error': message}

class Pipeline:
    def __init__(self):
        self.middleware = []
    def use(self, handler, name=None):
        self.middleware.append({'handler': handler, 'name': name or handler.__name__})
        return self
    def execute(self, request):
        ctx = Context(request)
        idx = 0
        def next_handler():
            nonlocal idx
            if ctx.aborted or idx >= len(self.middleware):
                return
            current = self.middleware[idx]
            idx += 1
            print(f'  [{current["name"]}] processing...')
            current['handler'](ctx, next_handler)
        next_handler()
        return ctx

# Demo middleware
def logging_middleware(ctx, next):
    start = time.time()
    next()
    elapsed = (time.time() - start) * 1000
    print(f'  [logging] {ctx.request.get("method", "?")} {ctx.request.get("path", "?")} -> {elapsed:.1f}ms')

def auth_middleware(ctx, next):
    token = ctx.request.get('headers', {}).get('Authorization')
    if not token:
        ctx.abort(401, 'Unauthorized: missing token')
        return
    ctx.metadata['user'] = 'authenticated_user'
    next()

def rate_limit_middleware(ctx, next):
    ctx.metadata['rate_limit_remaining'] = 99
    next()

def handler_middleware(ctx, next):
    path = ctx.request.get('path', '/')
    if path == '/api/users':
        ctx.response = {'status': 200, 'body': [{'id': 1, 'name': 'Alice'}, {'id': 2, 'name': 'Bob'}]}
    elif path == '/api/health':
        ctx.response = {'status': 200, 'body': {'status': 'ok'}}
    else:
        ctx.response = {'status': 404, 'body': {'error': 'Not found'}}
    next()

pipeline = Pipeline()
pipeline.use(logging_middleware, 'logger')
pipeline.use(auth_middleware, 'auth')
pipeline.use(rate_limit_middleware, 'rate_limit')
pipeline.use(handler_middleware, 'handler')

print('Middleware Pipeline Demo:')
print('\nRequest 1 (authenticated):')
ctx1 = pipeline.execute({'method': 'GET', 'path': '/api/users', 'headers': {'Authorization': 'Bearer xyz'}})
print(f'  Response: {ctx1.response}')

print('\nRequest 2 (no auth):')
ctx2 = pipeline.execute({'method': 'GET', 'path': '/api/users', 'headers': {}})
print(f'  Response: {ctx2.response}')
print('Pipeline demo complete')

