import time
import uuid
from collections import defaultdict
from typing import Dict, List, Any

class WriteModel:
    def __init__(self):
        self.events = []
        self.subscribers = []
    def execute_command(self, command_type, data):
        event = {'id': str(uuid.uuid4())[:8], 'type': command_type, 'data': data, 'timestamp': time.time()}
        self.events.append(event)
        for sub in self.subscribers:
            sub.handle_event(event)
        return event
    def subscribe(self, read_model):
        self.subscribers.append(read_model)

class ReadModel:
    def __init__(self):
        self.state = {}
    def handle_event(self, event): pass
    def query(self, query_type, **params): pass

class UserReadModel(ReadModel):
    def __init__(self):
        super().__init__()
        self.users = {}
        self.user_count = 0
        self.email_index = {}
    def handle_event(self, event):
        data = event['data']
        if event['type'] == 'user_created':
            self.users[data['id']] = {'id': data['id'], 'name': data['name'], 'email': data['email'], 'active': True}
            self.email_index[data['email']] = data['id']
            self.user_count += 1
        elif event['type'] == 'user_updated':
            if data['id'] in self.users:
                self.users[data['id']].update(data.get('changes', {}))
        elif event['type'] == 'user_deactivated':
            if data['id'] in self.users:
                self.users[data['id']]['active'] = False
    def query(self, query_type, **params):
        if query_type == 'get_user':
            return self.users.get(params.get('id'))
        elif query_type == 'list_active':
            return [u for u in self.users.values() if u['active']]
        elif query_type == 'find_by_email':
            uid = self.email_index.get(params.get('email'))
            return self.users.get(uid) if uid else None
        elif query_type == 'count':
            return self.user_count

# Demo
write = WriteModel()
read = UserReadModel()
write.subscribe(read)

print('CQRS Pattern Demo:')
print('\nWrite side (commands):')
write.execute_command('user_created', {'id': 'u1', 'name': 'Alice', 'email': 'alice@example.com'})
write.execute_command('user_created', {'id': 'u2', 'name': 'Bob', 'email': 'bob@example.com'})
write.execute_command('user_created', {'id': 'u3', 'name': 'Charlie', 'email': 'charlie@example.com'})
write.execute_command('user_updated', {'id': 'u1', 'changes': {'name': 'Alice Smith'}})
write.execute_command('user_deactivated', {'id': 'u2'})

print(f'\nRead side (queries):')
print(f'  Get user u1: {read.query("get_user", id="u1")}')
print(f'  Active users: {read.query("list_active")}')
print(f'  Find by email: {read.query("find_by_email", email="charlie@example.com")}')
print(f'  Total users: {read.query("count")}')
print(f'  Write events: {len(write.events)}')
print('CQRS demo complete')

