import json
import hashlib
import time
from typing import Dict, Optional, Any

class FeatureFlagManager:
    def __init__(self, config=None):
        self.flags = {}
        self.overrides = {}
        if config:
            self.load_config(config)
    def load_config(self, config):
        if isinstance(config, str):
            config = json.loads(config)
        for name, settings in config.items():
            self.flags[name] = {'enabled': settings.get('enabled', False), 'percentage': settings.get('percentage', 100), 'whitelist': set(settings.get('whitelist', [])), 'blacklist': set(settings.get('blacklist', [])), 'variants': settings.get('variants', {}), 'description': settings.get('description', '')}
    def is_enabled(self, flag_name, user_id=None, default=False):
        if flag_name in self.overrides:
            return self.overrides[flag_name]
        flag = self.flags.get(flag_name)
        if not flag:
            return default
        if not flag['enabled']:
            return False
        if user_id:
            if user_id in flag['blacklist']:
                return False
            if user_id in flag['whitelist']:
                return True
            if flag['percentage'] < 100:
                hash_val = int(hashlib.md5(f'{flag_name}:{user_id}'.encode()).hexdigest()[:8], 16)
                return (hash_val % 100) < flag['percentage']
        return True
    def get_variant(self, flag_name, user_id=None, default=None):
        flag = self.flags.get(flag_name, {})
        variants = flag.get('variants', {})
        if not variants:
            return default
        if user_id:
            hash_val = int(hashlib.md5(f'{flag_name}:variant:{user_id}'.encode()).hexdigest()[:8], 16)
            keys = sorted(variants.keys())
            return keys[hash_val % len(keys)]
        return default
    def set_override(self, flag_name, value):
        self.overrides[flag_name] = value
    def clear_override(self, flag_name):
        self.overrides.pop(flag_name, None)
    def list_flags(self):
        return {name: {'enabled': f['enabled'], 'percentage': f['percentage']} for name, f in self.flags.items()}

# Demo
config = {
    'dark_mode': {'enabled': True, 'percentage': 100, 'description': 'Dark mode UI'},
