import threading
from typing import Dict, Any, Callable, Optional
from enum import Enum

class Lifecycle(Enum):
    SINGLETON = 'singleton'
    TRANSIENT = 'transient'

class ServiceLocator:
    _instance = None
    _lock = threading.Lock()
    def __init__(self):
        self.registry: Dict[str, dict] = {}
        self.singletons: Dict[str, Any] = {}
    @classmethod
    def instance(cls):
        if cls._instance is None:
            with cls._lock:
                if cls._instance is None:
                    cls._instance = cls()
        return cls._instance
    def register(self, name, factory, lifecycle=Lifecycle.SINGLETON):
        self.registry[name] = {'factory': factory, 'lifecycle': lifecycle}
        if name in self.singletons:
            del self.singletons[name]
        print(f'  Registered: {name} ({lifecycle.value})')
    def resolve(self, name):
        if name not in self.registry:
            raise KeyError(f'Service "{name}" not registered')
        entry = self.registry[name]
        if entry['lifecycle'] == Lifecycle.SINGLETON:
            if name not in self.singletons:
                self.singletons[name] = entry['factory']()
            return self.singletons[name]
        return entry['factory']()
    def has(self, name):
        return name in self.registry
    def unregister(self, name):
        self.registry.pop(name, None)
        self.singletons.pop(name, None)
    def list_services(self):
        return {name: entry['lifecycle'].value for name, entry in self.registry.items()}
    def reset(self):
        self.registry.clear()
        self.singletons.clear()

# Demo
class Logger:
    _count = 0
    def __init__(self):
        Logger._count += 1
        self.id = Logger._count
    def log(self, msg): print(f'    [Logger#{self.id}] {msg}')

class Database:
    _count = 0
    def __init__(self):
        Database._count += 1
        self.id = Database._count
    def query(self, sql): return f'DB#{self.id} result for: {sql}'

class RequestHandler:
    _count = 0
    def __init__(self):
        RequestHandler._count += 1
        self.id = RequestHandler._count
    def handle(self): return f'Handler#{self.id} processed request'

locator = ServiceLocator()
print('Service Locator Demo:')
locator.register('logger', Logger, Lifecycle.SINGLETON)
locator.register('database', Database, Lifecycle.SINGLETON)
locator.register('handler', RequestHandler, Lifecycle.TRANSIENT)

print(f'\nServices: {locator.list_services()}')

log1 = locator.resolve('logger')
log2 = locator.resolve('logger')
print(f'\nSingleton test: logger1.id={log1.id}, logger2.id={log2.id} (same={log1 is log2})')

h1 = locator.resolve('handler')
h2 = locator.resolve('handler')
print(f'Transient test: handler1.id={h1.id}, handler2.id={h2.id} (same={h1 is h2})')

log1.log('Service locator working!')
db = locator.resolve('database')
print(f'DB query: {db.query("SELECT 1")}')
print('Service locator demo complete')

