import time
import traceback
from abc import ABC, abstractmethod
from typing import List, Any, Dict, Optional
from dataclasses import dataclass, field

@dataclass
class PipelineResult:
    stage: str
    success: bool
    data: Any = None
    error: str = None
    duration: float = 0

class Stage(ABC):
    def __init__(self, name):
        self.name = name
    @abstractmethod
    def process(self, data, context) -> Any: pass

class ExtractStage(Stage):
    def __init__(self, name, extractor):
        super().__init__(name)
        self.extractor = extractor
    def process(self, data, context):
        return self.extractor(context)

class TransformStage(Stage):
    def __init__(self, name, transformer):
        super().__init__(name)
        self.transformer = transformer
    def process(self, data, context):
        return self.transformer(data, context)

class LoadStage(Stage):
    def __init__(self, name, loader):
        super().__init__(name)
        self.loader = loader
    def process(self, data, context):
        return self.loader(data, context)

class Pipeline:
    def __init__(self, name):
        self.name = name
        self.stages: List[Stage] = []
        self.error_handlers = {}
        self.results: List[PipelineResult] = []
    def extract(self, name, func):
        self.stages.append(ExtractStage(name, func)); return self
    def transform(self, name, func):
        self.stages.append(TransformStage(name, func)); return self
    def load(self, name, func):
        self.stages.append(LoadStage(name, func)); return self
    def on_error(self, stage_name, handler):
        self.error_handlers[stage_name] = handler; return self
    def run(self, context=None):
        context = context or {}
        data = None
        print(f'Pipeline [{self.name}] starting ({len(self.stages)} stages)')
        for stage in self.stages:
            start = time.time()
            try:
                data = stage.process(data, context)
                result = PipelineResult(stage=stage.name, success=True, data=data, duration=time.time()-start)
                self.results.append(result)
                print(f'  [{stage.name}] OK ({result.duration:.3f}s)')
            except Exception as e:
                result = PipelineResult(stage=stage.name, success=False, error=str(e), duration=time.time()-start)
                self.results.append(result)
                print(f'  [{stage.name}] FAILED: {e}')
                handler = self.error_handlers.get(stage.name)
                if handler:
                    data = handler(e, data, context)
                    print(f'  [{stage.name}] Error handled, continuing')
                else:
                    print(f'Pipeline [{self.name}] aborted at {stage.name}')
                    return self.results
        print(f'Pipeline [{self.name}] completed')
        return self.results
    def summary(self):
        total = sum(r.duration for r in self.results)
        ok = sum(1 for r in self.results if r.success)
        return {'pipeline': self.name, 'stages': len(self.results), 'succeeded': ok, 'failed': len(self.results)-ok, 'total_time': f'{total:.3f}s'}

# Demo
def extract_data(ctx):
    return [{'name': 'Alice', 'age': 30, 'salary': 75000}, {'name': 'Bob', 'age': 25, 'salary': 55000}, {'name': 'Charlie', 'age': 35, 'salary': 90000}, {'name': '', 'age': -1, 'salary': 0}]

def clean_data(data, ctx):
    return [r for r in data if r['name'] and r['age'] > 0]

def enrich_data(data, ctx):
    for r in data:
        r['tax_bracket'] = 'high' if r['salary'] > 70000 else 'standard'
        r['senior'] = r['age'] >= 30
    return data

def load_to_store(data, ctx):
    ctx['loaded_records'] = len(data)
    for r in data:
        print(f'    Loaded: {r}')
    return data

pipeline = Pipeline('employee-etl')
pipeline.extract('fetch_employees', extract_data)
pipeline.transform('clean', clean_data)
pipeline.transform('enrich', enrich_data)
pipeline.load('store', load_to_store)

ctx = {}
pipeline.run(ctx)
print(f'\nSummary: {pipeline.summary()}')
print(f'Records loaded: {ctx.get("loaded_records", 0)}')

