import re
import json
from typing import Dict, List, Callable, Any, Optional
from http.server import HTTPServer, BaseHTTPRequestHandler
import urllib.parse

class Request:
    def __init__(self, method, path, headers, body='', query_params=None):
        self.method = method
        self.path = path
        self.headers = headers or {}
        self.body = body
        self.query_params = query_params or {}
        self.params = {}
    def json(self):
        return json.loads(self.body) if self.body else {}

class Response:
    def __init__(self, body='', status=200, content_type='text/html'):
        self.body = body
        self.status = status
        self.headers = {'Content-Type': content_type}
    @staticmethod
    def json(data, status=200):
        r = Response(json.dumps(data), status, 'application/json')
        return r
    @staticmethod
    def html(body, status=200):
        return Response(body, status, 'text/html')

class Router:
    def __init__(self):
        self.routes = []
    def add_route(self, method, pattern, handler):
        regex = re.sub(r':([\w]+)', r'(?P<\1>[\w-]+)', pattern)
        self.routes.append({'method': method, 'pattern': re.compile(f'^{regex}$'), 'handler': handler, 'path': pattern})
    def match(self, method, path):
        for route in self.routes:
            if route['method'] == method:
                m = route['pattern'].match(path)
                if m:
                    return route['handler'], m.groupdict()
        return None, {}

class MiniFramework:
    def __init__(self):
        self.router = Router()
        self.middleware = []
        self.templates = {}
    def route(self, path, methods=None):
        methods = methods or ['GET']
        def decorator(func):
            for method in methods:
                self.router.add_route(method, path, func)
            return func
        return decorator
    def use(self, middleware_func):
        self.middleware.append(middleware_func)
    def template(self, name, content):
        self.templates[name] = content
    def render(self, name, **context):
        tmpl = self.templates.get(name, '')
        for key, value in context.items():
            tmpl = tmpl.replace('{{' + key + '}}', str(value))
        return tmpl
    def handle_request(self, method, path, headers=None, body=''):
        parsed = urllib.parse.urlparse(path)
        query = dict(urllib.parse.parse_qsl(parsed.query))
        req = Request(method, parsed.path, headers or {}, body, query)
        for mw in self.middleware:
            result = mw(req)
            if isinstance(result, Response):
                return result
        handler, params = self.router.match(method, parsed.path)
        if not handler:
            return Response.json({'error': 'Not found'}, 404)
        req.params = params
        try:
            return handler(req)
        except Exception as e:
            return Response.json({'error': str(e)}, 500)

# Demo
app = MiniFramework()
app.template('index', '<html><body><h1>{{title}}</h1><p>{{message}}</p></body></html>')

def log_middleware(req):
    print(f'  [{req.method}] {req.path}')

app.use(log_middleware)

@app.route('/')
def index(req):
    html = app.render('index', title='Welcome', message='Mini Framework Works!')
    return Response.html(html)

@app.route('/api/users')
def list_users(req):
    return Response.json([{'id': 1, 'name': 'Alice'}, {'id': 2, 'name': 'Bob'}])

@app.route('/api/users/:id')
def get_user(req):
    return Response.json({'id': req.params['id'], 'name': 'User ' + req.params['id']})

@app.route('/api/users', methods=['POST'])
def create_user(req):
    return Response.json({'created': True, 'data': req.json()}, 201)

print('Mini Web Framework Demo:')
for method, path in [('GET', '/'), ('GET', '/api/users'), ('GET', '/api/users/42'), ('POST', '/api/users'), ('GET', '/not-found')]:
    resp = app.handle_request(method, path, body='{"name":"test"}')
    print(f'  -> {resp.status}: {resp.body[:60]}...' if len(resp.body) > 60 else f'  -> {resp.status}: {resp.body}')
print('Framework demo complete')

