import re
import math
from collections import defaultdict, Counter
from typing import List, Set, Dict, Optional

class InvertedIndex:
    def __init__(self):
        self.index: Dict[str, Dict[int, List[int]]] = defaultdict(lambda: defaultdict(list))
        self.documents: Dict[int, str] = {}
        self.doc_lengths: Dict[int, int] = {}
        self.doc_count = 0
    def add_document(self, doc_id, text):
        self.documents[doc_id] = text
        tokens = self._tokenize(text)
        self.doc_lengths[doc_id] = len(tokens)
        self.doc_count += 1
        for pos, token in enumerate(tokens):
            self.index[token][doc_id].append(pos)
    def search(self, query, mode='AND'):
        terms = self._tokenize(query)
        if not terms:
            return []
        if mode == 'AND':
            result_docs = None
            for term in terms:
                docs = set(self.index.get(term, {}).keys())
                result_docs = docs if result_docs is None else result_docs & docs
            return sorted(result_docs) if result_docs else []
        elif mode == 'OR':
            result_docs = set()
            for term in terms:
                result_docs |= set(self.index.get(term, {}).keys())
            return sorted(result_docs)
        elif mode == 'NOT':
            if len(terms) < 2:
                return []
            include = set(self.index.get(terms[0], {}).keys())
            for term in terms[1:]:
                include -= set(self.index.get(term, {}).keys())
            return sorted(include)
    def search_phrase(self, phrase):
        terms = self._tokenize(phrase)
        if not terms:
            return []
        candidate_docs = set(self.index.get(terms[0], {}).keys())
        for term in terms[1:]:
            candidate_docs &= set(self.index.get(term, {}).keys())
        results = []
        for doc_id in candidate_docs:
            positions = [self.index[terms[0]][doc_id]]
            for i, term in enumerate(terms[1:], 1):
                positions.append([p - i for p in self.index[term][doc_id]])
            common = set(positions[0])
            for pos_list in positions[1:]:
                common &= set(pos_list)
            if common:
                results.append(doc_id)
        return sorted(results)
    def get_tf_idf(self, term, doc_id):
        if term not in self.index or doc_id not in self.index[term]:
            return 0.0
        tf = len(self.index[term][doc_id]) / self.doc_lengths.get(doc_id, 1)
        idf = math.log(self.doc_count / len(self.index[term]))
        return tf * idf
    def _tokenize(self, text):
        return re.findall(r'\w+', text.lower())
    def stats(self):
        return {'documents': self.doc_count, 'unique_terms': len(self.index), 'avg_doc_length': sum(self.doc_lengths.values()) / max(self.doc_count, 1)}

# Demo
idx = InvertedIndex()
print('Inverted Index Demo:')
docs = [
    (1, 'The quick brown fox jumps over the lazy dog'),
    (2, 'A quick red fox runs through the forest'),
    (3, 'The lazy dog sleeps all day long'),
    (4, 'Brown bears and brown foxes live in the forest'),
    (5, 'The dog and the fox are friends'),
]
for doc_id, text in docs:
    idx.add_document(doc_id, text)
    print(f'  Added doc {doc_id}: "{text[:40]}..."')

print(f'\nStats: {idx.stats()}')
print(f'\nBoolean queries:')
print(f'  AND("quick fox"): docs {idx.search("quick fox", "AND")}')
print(f'  OR("lazy bears"): docs {idx.search("lazy bears", "OR")}')
print(f'  NOT("dog lazy"): docs {idx.search("dog lazy", "NOT")}')
print(f'\nPhrase search("the lazy dog"): docs {idx.search_phrase("the lazy dog")}')
print(f'TF-IDF("fox", doc 1): {idx.get_tf_idf("fox", 1):.4f}')
print(f'TF-IDF("fox", doc 4): {idx.get_tf_idf("fox", 4):.4f}')

