import json
import re
import operator
from typing import Dict, List, Any, Callable, Optional

class Rule:
    OPERATORS = {'eq': operator.eq, 'ne': operator.ne, 'gt': operator.gt, 'lt': operator.lt, 'gte': operator.ge, 'lte': operator.le, 'contains': lambda a, b: b in a, 'matches': lambda a, b: bool(re.search(b, str(a)))}
    def __init__(self, name, conditions, actions, priority=0):
        self.name = name
        self.conditions = conditions
        self.actions = actions
        self.priority = priority
        self.fire_count = 0
    def evaluate(self, data):
        for cond in self.conditions:
            field = cond['field']
            op = cond['operator']
            expected = cond['value']
            actual = self._get_nested(data, field)
            if actual is None:
                return False
            op_func = self.OPERATORS.get(op)
            if not op_func:
                return False
            if not op_func(actual, expected):
                return False
        return True
    def _get_nested(self, data, path):
        parts = path.split('.')
        current = data
        for part in parts:
            if isinstance(current, dict):
                current = current.get(part)
            else:
                return None
        return current

class RuleEngine:
    def __init__(self):
        self.rules: List[Rule] = []
        self.action_handlers: Dict[str, Callable] = {}
    def add_rule(self, name, conditions, actions, priority=0):
        rule = Rule(name, conditions, actions, priority)
        self.rules.append(rule)
        self.rules.sort(key=lambda r: r.priority, reverse=True)
        return rule
    def register_action(self, name, handler):
        self.action_handlers[name] = handler
    def evaluate(self, data):
        fired = []
        for rule in self.rules:
            if rule.evaluate(data):
                rule.fire_count += 1
                fired.append(rule.name)
                for action in rule.actions:
                    handler = self.action_handlers.get(action['type'])
                    if handler:
                        handler(data, action.get('params', {}))
        return fired
    def load_rules(self, config):
        if isinstance(config, str):
            config = json.loads(config)
        for rule_def in config:
            self.add_rule(rule_def['name'], rule_def['conditions'], rule_def['actions'], rule_def.get('priority', 0))
    def stats(self):
        return {r.name: r.fire_count for r in self.rules}

# Demo
engine = RuleEngine()
results = []
def log_action(data, params): results.append(f'LOG: {params.get("message", "")} for {data.get("name", "?")}')
def alert_action(data, params): results.append(f'ALERT: {params.get("level", "info")} - {data.get("name", "?")}')
def discount_action(data, params): results.append(f'DISCOUNT: {params.get("percent", 0)}% for {data.get("name", "?")}')

engine.register_action('log', log_action)
engine.register_action('alert', alert_action)
engine.register_action('discount', discount_action)

rules_config = [
    {'name': 'vip_customer', 'priority': 10, 'conditions': [{'field': 'total_purchases', 'operator': 'gte', 'value': 1000}], 'actions': [{'type': 'discount', 'params': {'percent': 20}}, {'type': 'log', 'params': {'message': 'VIP discount applied'}}]},
    {'name': 'high_risk_order', 'priority': 20, 'conditions': [{'field': 'order.amount', 'operator': 'gt', 'value': 500}, {'field': 'order.country', 'operator': 'ne', 'value': 'US'}], 'actions': [{'type': 'alert', 'params': {'level': 'warning'}}]},
    {'name': 'new_customer_welcome', 'priority': 5, 'conditions': [{'field': 'total_purchases', 'operator': 'eq', 'value': 0}], 'actions': [{'type': 'discount', 'params': {'percent': 10}}, {'type': 'log', 'params': {'message': 'Welcome discount'}}]}
]
engine.load_rules(rules_config)

print('Rule Engine Demo:')
test_data = [
    {'name': 'Alice', 'total_purchases': 1500, 'order': {'amount': 200, 'country': 'US'}},
    {'name': 'Bob', 'total_purchases': 0, 'order': {'amount': 50, 'country': 'US'}},
    {'name': 'Charlie', 'total_purchases': 300, 'order': {'amount': 800, 'country': 'UK'}},
]

for data in test_data:
    fired = engine.evaluate(data)
    print(f'  {data["name"]}: rules fired = {fired}')

print(f'\nActions triggered:')
for r in results:
