import json
import os
from copy import deepcopy

class Config:
    def __init__(self, base=None):
        self._data = deepcopy(base) if base else {}
        self._parent = None
    def set(self, key, value):
        keys = key.split('.')
        d = self._data
        for k in keys[:-1]:
            if k not in d: d[k] = {}
            d = d[k]
        d[keys[-1]] = value
    def get(self, key, default=None):
        keys = key.split('.')
        d = self._data
        for k in keys:
            if isinstance(d, dict) and k in d: d = d[k]
            else:
                return self._parent.get(key, default) if self._parent else default
        return d
    def inherit(self, parent):
        self._parent = parent
        return self
    def from_env(self, prefix='APP'):
        for key, value in os.environ.items():
            if key.startswith(prefix + '_'):
                config_key = key[len(prefix)+1:].lower().replace('__', '.')
                self.set(config_key, value)
        return self
    def merge(self, other):
        def _merge(base, overlay):
            for k, v in overlay.items():
                if k in base and isinstance(base[k], dict) and isinstance(v, dict):
                    _merge(base[k], v)
                else: base[k] = deepcopy(v)
        src = other._data if isinstance(other, Config) else other
        _merge(self._data, src)
        return self
    def to_dict(self):
        result = self._parent.to_dict() if self._parent else {}
        def _merge(base, overlay):
            for k, v in overlay.items():
                if k in base and isinstance(base[k], dict) and isinstance(v, dict):
                    _merge(base[k], v)
                else: base[k] = v
        _merge(result, deepcopy(self._data))
        return result

base = Config({'database': {'host': 'localhost', 'port': 5432}, 'debug': False, 'log_level': 'INFO'})
dev = Config({'debug': True, 'log_level': 'DEBUG'}).inherit(base)
prod = Config({'database': {'host': 'db.prod.example.com', 'pool_size': 20}}).inherit(base)
os.environ['APP_DATABASE__HOST'] = 'override.example.com'
prod.from_env('APP')
print('Config Inheritance Demo:')
print(f'Base: {json.dumps(base.to_dict())}')
print(f'Dev (inherits base): {json.dumps(dev.to_dict())}')
print(f'Dev debug: {dev.get("debug")}')
print(f'Dev db host (inherited): {dev.get("database.host")}')
print(f'Prod with env: {json.dumps(prod.to_dict())}')
print(f'Prod log_level (inherited): {prod.get("log_level")}')

