import time
import threading
import json
from collections import deque
from datetime import datetime

class LogEntry:
    def __init__(self, source, level, message, metadata=None):
        self.source = source
        self.level = level
        self.message = message
        self.metadata = metadata or {}
        self.timestamp = time.time()
    def to_dict(self):
        return {'source': self.source, 'level': self.level, 'message': self.message, 'metadata': self.metadata, 'ts': self.timestamp}

class LogAggregator:
    LEVELS = {'DEBUG': 0, 'INFO': 1, 'WARNING': 2, 'ERROR': 3, 'CRITICAL': 4}
    def __init__(self, max_entries=10000):
        self.entries = deque(maxlen=max_entries)
        self.sources = set()
        self.lock = threading.Lock()
        self.handlers = []
    def ingest(self, source, level, message, metadata=None):
        entry = LogEntry(source, level.upper(), message, metadata)
        with self.lock:
            self.entries.append(entry)
            self.sources.add(source)
        for handler in self.handlers:
            handler(entry)
        return entry
    def query(self, source=None, level=None, keyword=None, last_n=None):
        with self.lock:
            results = list(self.entries)
        if source:
            results = [e for e in results if e.source == source]
        if level:
            min_level = self.LEVELS.get(level.upper(), 0)
            results = [e for e in results if self.LEVELS.get(e.level, 0) >= min_level]
        if keyword:
            results = [e for e in results if keyword.lower() in e.message.lower()]
        if last_n:
            results = results[-last_n:]
        return results
    def add_handler(self, handler):
