import re
import json
from typing import Any, Dict, List, Optional

class ValidationError:
    def __init__(self, field, message, value=None):
        self.field = field
        self.message = message
        self.value = value
    def __repr__(self):
        return f'{self.field}: {self.message}'

class Validator:
    def __init__(self):
        self.rules = {}
        self.nested = {}
    def field(self, name, **kwargs):
        self.rules[name] = kwargs
        return self
    def nested_validator(self, name, validator):
        self.nested[name] = validator
        return self
    def validate(self, data, prefix=''):
        errors = []
        for field, rules in self.rules.items():
            full_field = f'{prefix}{field}' if not prefix else f'{prefix}.{field}'
            value = data.get(field) if isinstance(data, dict) else None
            if rules.get('required') and (value is None or value == ''):
                errors.append(ValidationError(full_field, 'is required'))
                continue
            if value is None: continue
            if 'type' in rules and not isinstance(value, rules['type']):
                errors.append(ValidationError(full_field, f'must be {rules["type"].__name__}', value))
            if 'min' in rules and isinstance(value, (int, float)) and value < rules['min']:
                errors.append(ValidationError(full_field, f'must be >= {rules["min"]}', value))
            if 'max' in rules and isinstance(value, (int, float)) and value > rules['max']:
                errors.append(ValidationError(full_field, f'must be <= {rules["max"]}', value))
            if 'min_length' in rules and isinstance(value, str) and len(value) < rules['min_length']:
                errors.append(ValidationError(full_field, f'min length {rules["min_length"]}', value))
            if 'max_length' in rules and isinstance(value, str) and len(value) > rules['max_length']:
                errors.append(ValidationError(full_field, f'max length {rules["max_length"]}', value))
            if 'pattern' in rules and isinstance(value, str) and not re.match(rules['pattern'], value):
                errors.append(ValidationError(full_field, f'must match pattern {rules["pattern"]}', value))
            if 'choices' in rules and value not in rules['choices']:
                errors.append(ValidationError(full_field, f'must be one of {rules["choices"]}', value))
            if 'custom' in rules:
                msg = rules['custom'](value)
                if msg: errors.append(ValidationError(full_field, msg, value))
        for name, validator in self.nested.items():
            nested_data = data.get(name, {}) if isinstance(data, dict) else {}
            prefix_path = f'{prefix}.{name}' if prefix else name
            errors.extend(validator.validate(nested_data, prefix_path))
        return errors

