import os
import time
import json
import threading

class FileLock:
    def __init__(self, lock_path, timeout=10, stale_timeout=30):
        self.lock_path = lock_path
        self.timeout = timeout
        self.stale_timeout = stale_timeout
        self.acquired = False
    def acquire(self):
        deadline = time.time() + self.timeout
        while time.time() < deadline:
            try:
                if os.path.exists(self.lock_path):
                    try:
                        with open(self.lock_path) as f:
                            info = json.load(f)
                        if time.time() - info.get('timestamp', 0) > self.stale_timeout:
                            print(f'  Removing stale lock (age: {time.time() - info["timestamp"]:.0f}s)')
                            os.remove(self.lock_path)
                        else:
                            time.sleep(0.1)
                            continue
                    except (json.JSONDecodeError, KeyError):
                        os.remove(self.lock_path)
                fd = os.open(self.lock_path, os.O_CREAT | os.O_EXCL | os.O_WRONLY)
                info = {'pid': os.getpid(), 'timestamp': time.time(), 'thread': threading.current_thread().name}
                os.write(fd, json.dumps(info).encode())
                os.close(fd)
                self.acquired = True
                return True
            except FileExistsError:
                time.sleep(0.1)
        return False
    def release(self):
        if self.acquired and os.path.exists(self.lock_path):
            os.remove(self.lock_path)
            self.acquired = False
    def __enter__(self):
        if not self.acquire():
            raise TimeoutError(f'Could not acquire lock: {self.lock_path}')
        return self
    def __exit__(self, *args):
        self.release()
    def is_locked(self):
        return os.path.exists(self.lock_path)
    def lock_info(self):
        if os.path.exists(self.lock_path):
            with open(self.lock_path) as f:
                return json.load(f)
        return None

import tempfile
lock_path = os.path.join(tempfile.gettempdir(), 'forge_test.lock')
if os.path.exists(lock_path): os.remove(lock_path)

print('Distributed File Lock Demo:')
lock = FileLock(lock_path, timeout=5, stale_timeout=10)
print(f'Lock path: {lock_path}')
print(f'Locked before: {lock.is_locked()}')

with FileLock(lock_path, timeout=5) as lk:
    print(f'Lock acquired: {lk.acquired}')
    print(f'Lock info: {lk.lock_info()}')
    lock2 = FileLock(lock_path, timeout=0.3)
    result = lock2.acquire()
    print(f'Second lock attempt: {result}')

print(f'Lock released: {not lock.is_locked()}')

with FileLock(lock_path, timeout=5) as lk:
    print(f'Re-acquired after release: {lk.acquired}')
print(f'Final state - locked: {lock.is_locked()}')
if os.path.exists(lock_path): os.remove(lock_path)

