import time
import threading
import math
from collections import defaultdict

class Counter:
    def __init__(self, name, description=''):
        self.name = name
        self.description = description
        self._value = 0
        self._lock = threading.Lock()
    def inc(self, amount=1):
        with self._lock: self._value += amount
    def value(self):
        return self._value

class Gauge:
    def __init__(self, name, description=''):
        self.name = name
        self.description = description
        self._value = 0
        self._lock = threading.Lock()
    def set(self, value):
        with self._lock: self._value = value
    def inc(self, amount=1):
        with self._lock: self._value += amount
    def dec(self, amount=1):
        with self._lock: self._value -= amount
    def value(self):
        return self._value

class Histogram:
    def __init__(self, name, buckets=None, description=''):
        self.name = name
        self.description = description
        self.buckets = sorted(buckets or [0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0])
        self._counts = defaultdict(int)
        self._sum = 0
        self._count = 0
        self._lock = threading.Lock()
    def observe(self, value):
        with self._lock:
            self._sum += value
            self._count += 1
            for b in self.buckets:
                if value <= b:
                    self._counts[b] += 1
    def percentile(self, p):
        if self._count == 0: return 0
        target = self._count * p / 100
        cumulative = 0
        for b in self.buckets:
            cumulative += self._counts.get(b, 0)
            if cumulative >= target: return b
        return self.buckets[-1]
    def stats(self):
        return {'count': self._count, 'sum': round(self._sum, 4), 'avg': round(self._sum / max(self._count, 1), 4), 'p50': self.percentile(50), 'p95': self.percentile(95), 'p99': self.percentile(99)}

class MetricsRegistry:
    def __init__(self):
        self._metrics = {}
    def counter(self, name, description=''):
        if name not in self._metrics:
            self._metrics[name] = Counter(name, description)
        return self._metrics[name]
    def gauge(self, name, description=''):
        if name not in self._metrics:
            self._metrics[name] = Gauge(name, description)
        return self._metrics[name]
    def histogram(self, name, buckets=None, description=''):
        if name not in self._metrics:
            self._metrics[name] = Histogram(name, buckets, description)
        return self._metrics[name]
    def collect(self):
        result = {}
        for name, m in self._metrics.items():
            if isinstance(m, Counter): result[name] = {'type': 'counter', 'value': m.value()}
            elif isinstance(m, Gauge): result[name] = {'type': 'gauge', 'value': m.value()}
            elif isinstance(m, Histogram): result[name] = {'type': 'histogram', **m.stats()}
        return result

registry = MetricsRegistry()
requests_total = registry.counter('http_requests_total', 'Total HTTP requests')
active_conns = registry.gauge('active_connections', 'Active connections')
latency = registry.histogram('request_duration_seconds', [0.01, 0.05, 0.1, 0.25, 0.5, 1.0])

