import random
from collections import deque

def generate_maze(width, height, seed=42):
    random.seed(seed)
    maze = [[1] * width for _ in range(height)]
    def carve(x, y):
        maze[y][x] = 0
        directions = [(0, 2), (2, 0), (0, -2), (-2, 0)]
        random.shuffle(directions)
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < width and 0 <= ny < height and maze[ny][nx] == 1:
                maze[y + dy // 2][x + dx // 2] = 0
                carve(nx, ny)
    carve(1, 1)
    maze[1][0] = 0  # entrance
    maze[height - 2][width - 1] = 0  # exit
    return maze

def solve_bfs(maze, start, end):
    height, width = len(maze), len(maze[0])
    queue = deque([(start, [start])])
    visited = {start}
    while queue:
        (x, y), path = queue.popleft()
        if (x, y) == end:
            return path
        for dx, dy in [(0, 1), (1, 0), (0, -1), (-1, 0)]:
            nx, ny = x + dx, y + dy
            if 0 <= nx < width and 0 <= ny < height and maze[ny][nx] == 0 and (nx, ny) not in visited:
                visited.add((nx, ny))
                queue.append(((nx, ny), path + [(nx, ny)]))
    return None

def print_maze(maze, path=None):
    path_set = set(path) if path else set()
    symbols = {0: ' ', 1: '#'}
    for y, row in enumerate(maze):
        line = ''
        for x, cell in enumerate(row):
            if (x, y) in path_set: line += '.'
            else: line += symbols.get(cell, '?')
        print(line)

width, height = 21, 15
maze = generate_maze(width, height)
start = (0, 1)
end = (width - 1, height - 2)

print(f'Maze ({width}x{height}) - BFS Solver:')
print('Unsolved:')
print_maze(maze)

path = solve_bfs(maze, start, end)
if path:
    print(f'\nSolved (path length: {len(path)}):')
    print_maze(maze, path)
    print(f'Start: {start}, End: {end}')
else:
    print('No solution found')

