import random
import time

class GameOfLife:
    def __init__(self, width=20, height=20, seed=None):
        self.width = width
        self.height = height
        if seed is not None: random.seed(seed)
        self.grid = [[random.choice([0, 0, 0, 1]) for _ in range(width)] for _ in range(height)]
        self.generation = 0
    def count_neighbors(self, x, y):
        count = 0
        for dy in [-1, 0, 1]:
            for dx in [-1, 0, 1]:
                if dx == 0 and dy == 0: continue
                nx, ny = (x + dx) % self.width, (y + dy) % self.height
                count += self.grid[ny][nx]
        return count
    def step(self):
        new_grid = [[0] * self.width for _ in range(self.height)]
        for y in range(self.height):
            for x in range(self.width):
                neighbors = self.count_neighbors(x, y)
                if self.grid[y][x] == 1:
                    new_grid[y][x] = 1 if neighbors in (2, 3) else 0
                else:
                    new_grid[y][x] = 1 if neighbors == 3 else 0
        self.grid = new_grid
        self.generation += 1
    def population(self):
        return sum(sum(row) for row in self.grid)
    def display(self):
        for row in self.grid:
            print(''.join('#' if cell else '.' for cell in row))
    def add_pattern(self, x, y, pattern):
        for dy, row in enumerate(pattern):
            for dx, cell in enumerate(row):
                if cell:
                    self.grid[(y + dy) % self.height][(x + dx) % self.width] = 1

