import re
from collections import deque
from urllib.parse import urljoin, urlparse

class WebCrawler:
    def __init__(self, max_depth=3, max_pages=100):
        self.max_depth = max_depth
        self.max_pages = max_pages
        self.visited = set()
        self.results = []
        self.link_graph = {}
    def extract_links(self, html, base_url):
        links = re.findall(r'href=["\']([^"\']+)["\']', html)
        resolved = []
        for link in links:
            full = urljoin(base_url, link)
            parsed = urlparse(full)
            if parsed.scheme in ('http', 'https'):
                clean = f'{parsed.scheme}://{parsed.netloc}{parsed.path}'
                resolved.append(clean)
        return list(set(resolved))
    def should_crawl(self, url, base_domain):
        parsed = urlparse(url)
        if parsed.netloc != base_domain: return False
        skip_ext = ('.jpg', '.png', '.gif', '.pdf', '.zip', '.css', '.js')
        if any(parsed.path.endswith(ext) for ext in skip_ext): return False
        return url not in self.visited
    def crawl(self, start_url, fetch_func=None):
        parsed = urlparse(start_url)
        base_domain = parsed.netloc
        queue = deque([(start_url, 0)])
        self.visited.add(start_url)
        while queue and len(self.results) < self.max_pages:
            url, depth = queue.popleft()
            try:
                html = fetch_func(url) if fetch_func else f'<html><a href="/page{len(self.results)+1}">link</a><a href="/page{len(self.results)+2}">link2</a></html>'
                links = self.extract_links(html, url)
                self.link_graph[url] = links
                self.results.append({'url': url, 'depth': depth, 'links_found': len(links)})
                print(f'  [{depth}] Crawled: {url} ({len(links)} links)')
                if depth < self.max_depth:
                    for link in links:
                        if self.should_crawl(link, base_domain):
                            self.visited.add(link)
                            queue.append((link, depth + 1))
            except Exception as e:
                print(f'  [{depth}] Error: {url} - {e}')
        return self.results
    def stats(self):
        return {'pages_crawled': len(self.results), 'unique_urls': len(self.visited), 'max_depth_reached': max((r['depth'] for r in self.results), default=0)}

