import hashlib
import os
import json
import tempfile
import time

class FileStore:
    def __init__(self, storage_dir=None):
        self.storage_dir = storage_dir or tempfile.mkdtemp(prefix='filestore_')
        os.makedirs(self.storage_dir, exist_ok=True)
        self.metadata = {}
    def upload(self, filename, content, uploader='anonymous'):
        if isinstance(content, str): content = content.encode()
        file_hash = hashlib.sha256(content).hexdigest()[:16]
        file_path = os.path.join(self.storage_dir, file_hash)
        with open(file_path, 'wb') as f:
            f.write(content)
        self.metadata[file_hash] = {
            'filename': filename, 'size': len(content), 'hash': file_hash,
            'uploader': uploader, 'uploaded_at': time.time(),
            'content_type': self._guess_type(filename), 'downloads': 0
        }
        return file_hash
    def download(self, file_hash):
        if file_hash not in self.metadata:
            return None, None
        file_path = os.path.join(self.storage_dir, file_hash)
        if not os.path.exists(file_path):
            return None, None
        self.metadata[file_hash]['downloads'] += 1
        with open(file_path, 'rb') as f:
            content = f.read()
        return content, self.metadata[file_hash]
    def list_files(self, uploader=None):
        files = list(self.metadata.values())
        if uploader:
            files = [f for f in files if f['uploader'] == uploader]
        return sorted(files, key=lambda f: f['uploaded_at'], reverse=True)
    def delete(self, file_hash):
        if file_hash in self.metadata:
            file_path = os.path.join(self.storage_dir, file_hash)
            if os.path.exists(file_path): os.remove(file_path)
            del self.metadata[file_hash]
            return True
        return False
    def _guess_type(self, filename):
        ext_map = {'.txt': 'text/plain', '.py': 'text/x-python', '.json': 'application/json',
                    '.html': 'text/html', '.csv': 'text/csv', '.jpg': 'image/jpeg', '.png': 'image/png'}
        ext = os.path.splitext(filename)[1].lower()
        return ext_map.get(ext, 'application/octet-stream')
    def stats(self):
        total_size = sum(m['size'] for m in self.metadata.values())
        return {'files': len(self.metadata), 'total_size': total_size, 'total_downloads': sum(m['downloads'] for m in self.metadata.values())}

store = FileStore()
print('File Sharing Server Demo:')
h1 = store.upload('readme.txt', 'This is a readme file with important instructions.', 'alice')
h2 = store.upload('config.json', json.dumps({'host': 'localhost', 'port': 8080}), 'bob')
