import json
import time
import hashlib
from abc import ABC, abstractmethod

class NotificationChannel(ABC):
    @abstractmethod
    def send(self, recipient, subject, body, **kwargs): pass
    @abstractmethod
    def name(self): pass

class EmailChannel(NotificationChannel):
    def __init__(self): self.sent = []
    def send(self, recipient, subject, body, **kwargs):
        msg = {'to': recipient, 'subject': subject, 'body': body, 'timestamp': time.time(), 'channel': 'email'}
        self.sent.append(msg)
        print(f'    [EMAIL] To: {recipient} | Subject: {subject}')
        return True
    def name(self): return 'email'

class WebhookChannel(NotificationChannel):
    def __init__(self, endpoint='https://hooks.example.com'): self.endpoint = endpoint; self.sent = []
    def send(self, recipient, subject, body, **kwargs):
        payload = {'recipient': recipient, 'subject': subject, 'body': body, 'url': self.endpoint}
        self.sent.append(payload)
        print(f'    [WEBHOOK] POST {self.endpoint} | {subject}')
        return True
    def name(self): return 'webhook'

class LogChannel(NotificationChannel):
    def __init__(self): self.log = []
    def send(self, recipient, subject, body, **kwargs):
        entry = f'[{time.strftime("%Y-%m-%d %H:%M:%S")}] NOTIFY {recipient}: {subject} - {body[:50]}'
        self.log.append(entry)
        print(f'    [LOG] {entry}')
        return True
    def name(self): return 'log'

class NotificationService:
    def __init__(self):
        self.channels = {}
        self.preferences = {}
        self.history = []
    def register_channel(self, channel):
        self.channels[channel.name()] = channel
    def set_preference(self, user, channels):
        self.preferences[user] = channels
    def notify(self, recipient, subject, body, channels=None, **kwargs):
        target_channels = channels or self.preferences.get(recipient, list(self.channels.keys()))
        results = {}
        print(f'  Notifying {recipient}:')
        for ch_name in target_channels:
            channel = self.channels.get(ch_name)
            if channel:
                try:
                    success = channel.send(recipient, subject, body, **kwargs)
                    results[ch_name] = success
                except Exception as e:
                    results[ch_name] = False
                    print(f'    [{ch_name.upper()}] FAILED: {e}')
        self.history.append({'recipient': recipient, 'subject': subject, 'channels': results, 'timestamp': time.time()})
        return results
    def broadcast(self, subject, body, **kwargs):
        results = {}
        for user in self.preferences:
            results[user] = self.notify(user, subject, body, **kwargs)
        return results
    def stats(self):
        return {'total_sent': len(self.history), 'channels': list(self.channels.keys()), 'users': list(self.preferences.keys())}

service = NotificationService()
service.register_channel(EmailChannel())
service.register_channel(WebhookChannel())
service.register_channel(LogChannel())

service.set_preference('alice', ['email', 'log'])
service.set_preference('bob', ['webhook', 'email'])
service.set_preference('charlie', ['log'])

print('Multi-Channel Notification Demo:')
service.notify('alice', 'Deploy Complete', 'Version 2.1.0 deployed to production successfully.')
service.notify('bob', 'Alert: High CPU', 'Server cpu-1 at 95% utilization for 5 minutes.', channels=['webhook', 'email'])
print('\nBroadcast:')
service.broadcast('Scheduled Maintenance', 'System maintenance window: Sunday 2am-4am UTC')
print(f'\nStats: {service.stats()}')

