import os
import hashlib
import shutil
import tempfile
import json

def file_hash(filepath):
    h = hashlib.sha256()
    with open(filepath, 'rb') as f:
        for chunk in iter(lambda: f.read(8192), b''):
            h.update(chunk)
    return h.hexdigest()[:16]

def scan_directory(dirpath):
    files = {}
    for root, dirs, filenames in os.walk(dirpath):
        for fname in filenames:
            full = os.path.join(root, fname)
            rel = os.path.relpath(full, dirpath)
            files[rel] = {'hash': file_hash(full), 'size': os.path.getsize(full), 'mtime': os.path.getmtime(full)}
    return files

def sync_directories(source, target, dry_run=False):
    src_files = scan_directory(source)
    tgt_files = scan_directory(target) if os.path.exists(target) else {}
    actions = {'copy': [], 'update': [], 'delete': [], 'unchanged': []}
    for rel, info in src_files.items():
        if rel not in tgt_files:
            actions['copy'].append(rel)
        elif tgt_files[rel]['hash'] != info['hash']:
            actions['update'].append(rel)
        else:
            actions['unchanged'].append(rel)
    for rel in tgt_files:
        if rel not in src_files:
            actions['delete'].append(rel)
    if not dry_run:
        os.makedirs(target, exist_ok=True)
        for rel in actions['copy'] + actions['update']:
            src_path = os.path.join(source, rel)
            tgt_path = os.path.join(target, rel)
            os.makedirs(os.path.dirname(tgt_path), exist_ok=True)
            shutil.copy2(src_path, tgt_path)
        for rel in actions['delete']:
            tgt_path = os.path.join(target, rel)
            if os.path.exists(tgt_path): os.remove(tgt_path)
    return actions

# Demo with temp directories
src = tempfile.mkdtemp(prefix='sync_src_')
tgt = tempfile.mkdtemp(prefix='sync_tgt_')

for name, content in [('readme.txt', 'Hello World'), ('src/main.py', 'print("hello")'), ('src/utils.py', 'def helper(): pass'), ('data/config.json', '{"key": "value"}')]:
    path = os.path.join(src, name)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w') as f: f.write(content)

# Pre-populate target with some files
for name, content in [('readme.txt', 'Hello World'), ('src/main.py', 'print("old version")'), ('old_file.txt', 'should be deleted')]:
    path = os.path.join(tgt, name)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w') as f: f.write(content)

print('File Sync Demo:')
print(f'Source: {src}')
print(f'Target: {tgt}')

print('\nDry run:')
actions = sync_directories(src, tgt, dry_run=True)
for action, files in actions.items():
    if files: print(f'  {action}: {files}')

print('\nExecuting sync:')
actions = sync_directories(src, tgt, dry_run=False)
for action, files in actions.items():
    if files: print(f'  {action}: {files}')

print('\nVerification:')
src_files = scan_directory(src)
tgt_files = scan_directory(tgt)
print(f'Source files: {list(src_files.keys())}')
print(f'Target files: {list(tgt_files.keys())}')
print(f'In sync: {all(src_files[k]["hash"] == tgt_files[k]["hash"] for k in src_files if k in tgt_files)}')

shutil.rmtree(src)
shutil.rmtree(tgt)

