import json
import zlib
import base64
import string

class JSONCompressor:
    def __init__(self):
        self.key_map = {}
        self.reverse_map = {}
        self._counter = 0
    def _short_key(self):
        chars = string.ascii_lowercase
        n = self._counter
        self._counter += 1
        if n < 26: return chars[n]
        result = ''
        while n >= 0:
            result = chars[n % 26] + result
            n = n // 26 - 1
            if n < 0: break
        return result
    def _shorten_keys(self, obj):
        if isinstance(obj, dict):
            result = {}
            for key, value in obj.items():
                if key not in self.key_map:
                    short = self._short_key()
                    self.key_map[key] = short
                    self.reverse_map[short] = key
                result[self.key_map[key]] = self._shorten_keys(value)
            return result
        elif isinstance(obj, list):
            return [self._shorten_keys(item) for item in obj]
        return obj
    def _restore_keys(self, obj):
        if isinstance(obj, dict):
            return {self.reverse_map.get(k, k): self._restore_keys(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [self._restore_keys(item) for item in obj]
        return obj
    def compress(self, data):
        self.key_map = {}
        self.reverse_map = {}
        self._counter = 0
        shortened = self._shorten_keys(data)
        package = {'d': shortened, 'm': self.reverse_map}
        json_bytes = json.dumps(package, separators=(',', ':')).encode()
        compressed = zlib.compress(json_bytes, level=9)
        return base64.b64encode(compressed).decode()
    def decompress(self, compressed_str):
        compressed = base64.b64decode(compressed_str)
        json_bytes = zlib.decompress(compressed)
        package = json.loads(json_bytes)
        self.reverse_map = package['m']
        return self._restore_keys(package['d'])

compressor = JSONCompressor()
print('JSON Compressor Demo:')
test_data = {
    'users': [
        {'username': 'alice', 'email': 'alice@example.com', 'preferences': {'theme': 'dark', 'language': 'en', 'notifications': True}},
        {'username': 'bob', 'email': 'bob@example.com', 'preferences': {'theme': 'light', 'language': 'de', 'notifications': False}},
        {'username': 'charlie', 'email': 'charlie@example.com', 'preferences': {'theme': 'dark', 'language': 'fr', 'notifications': True}},
    ],
    'metadata': {'version': '2.0', 'generated_at': '2025-01-01T00:00:00', 'record_count': 3}
}

original = json.dumps(test_data)
compressed = compressor.compress(test_data)
decompressed = compressor.decompress(compressed)

print(f'Original size:    {len(original)} bytes')
print(f'Compressed size:  {len(compressed)} bytes')
print(f'Ratio:            {len(compressed)/len(original)*100:.1f}%')
print(f'Savings:          {len(original)-len(compressed)} bytes ({(1-len(compressed)/len(original))*100:.1f}%)')
print(f'Roundtrip OK:     {decompressed == test_data}')
print(f'\nKey mapping: {compressor.key_map}')
print(f'Original (first 80): {original[:80]}...')
print(f'Compressed: {compressed[:60]}...')

