from functools import wraps

class TailCall:
    def __init__(self, func, *args, **kwargs):
        self.func = func
        self.args = args
        self.kwargs = kwargs

def trampoline(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
        while isinstance(result, TailCall):
            result = result.func(*result.args, **result.kwargs)
        return result
    wrapper._original = func
    return wrapper

@trampoline
def factorial(n, acc=1):
    if n <= 1:
        return acc
    return TailCall(factorial._original, n - 1, n * acc)

@trampoline
def fibonacci(n, a=0, b=1):
    if n == 0:
        return a
    return TailCall(fibonacci._original, n - 1, b, a + b)

@trampoline
def sum_range(n, acc=0):
    if n <= 0:
        return acc
    return TailCall(sum_range._original, n - 1, acc + n)

@trampoline
def gcd(a, b):
    if b == 0:
        return a
    return TailCall(gcd._original, b, a % b)

@trampoline
def collatz_steps(n, steps=0):
    if n == 1:
        return steps
    if n % 2 == 0:
        return TailCall(collatz_steps._original, n // 2, steps + 1)
    return TailCall(collatz_steps._original, 3 * n + 1, steps + 1)

print('Tail Call Trampoline Demo:')
print(f'factorial(10)  = {factorial(10)}')
print(f'factorial(20)  = {factorial(20)}')
print(f'fibonacci(50)  = {fibonacci(50)}')
print(f'fibonacci(100) = {fibonacci(100)}')
print(f'sum_range(1000) = {sum_range(1000)}')
print(f'gcd(48, 18)    = {gcd(48, 18)}')
print(f'gcd(1071, 462) = {gcd(1071, 462)}')
print(f'collatz(27)    = {collatz_steps(27)} steps')

# Deep recursion test - would overflow without trampoline
print(f'\nDeep recursion test:')
result = sum_range(50000)
print(f'sum_range(50000) = {result}')
print(f'Expected: {50000 * 50001 // 2}')
print(f'Correct: {result == 50000 * 50001 // 2}')

result = factorial(100)
print(f'factorial(100) has {len(str(result))} digits')
print(f'All trampoline tests passed!')

