import mmap
import os
import struct

class MemoryMappedReader:
    """Memory-mapped file reader for large binary files"""
    def __init__(self, filepath):
        self.filepath = filepath
        self.fd = None
        self.mm = None
        self.size = 0

    def open(self):
        self.fd = os.open(self.filepath, os.O_RDONLY)
        self.size = os.fstat(self.fd).st_size
        if self.size > 0:
            self.mm = mmap.mmap(self.fd, 0, access=mmap.ACCESS_READ)
        return self

    def read_at(self, offset, length):
        if self.mm is None:
            raise ValueError("File not opened")
        if offset + length > self.size:
            length = self.size - offset
        self.mm.seek(offset)
        return self.mm.read(length)

    def read_struct(self, offset, fmt):
        size = struct.calcsize(fmt)
        data = self.read_at(offset, size)
        return struct.unpack(fmt, data)

    def find(self, pattern, start=0):
        if self.mm is None:
            return -1
        return self.mm.find(pattern, start)

    def close(self):
        if self.mm:
            self.mm.close()
        if self.fd is not None:
            os.close(self.fd)

    def __enter__(self):
        return self.open()

    def __exit__(self, *args):
        self.close()

    def __len__(self):
        return self.size

# Demo
if __name__ == "__main__":
    test_path = "/tmp/test_mmap.bin"
    with open(test_path, "wb") as f:
        f.write(b"HEADER" + struct.pack("<I", 42) + bytes(100) + b"MARKER" + bytes(50))

    with MemoryMappedReader(test_path) as reader:
        print(f"File size: {len(reader)} bytes")
        header = reader.read_at(0, 6)
        print(f"Header: {header}")
        value = reader.read_struct(6, "<I")
        print(f"Value at offset 6: {value[0]}")
        pos = reader.find(b"MARKER")
        print(f"MARKER found at offset: {pos}")

    os.unlink(test_path)
    print("Memory-mapped file reader working correctly")

