import re

class ExpressionEvaluator:
    """Calculator that handles +, -, *, /, parentheses, and operator precedence"""

    def __init__(self):
        self.pos = 0
        self.expr = ""

    def evaluate(self, expression):
        self.expr = expression.replace(" ", "")
        self.pos = 0
        result = self._parse_expression()
        if self.pos != len(self.expr):
            raise ValueError(f"Unexpected character at position {self.pos}: {self.expr[self.pos]}")
        return result

    def _parse_expression(self):
        result = self._parse_term()
        while self.pos < len(self.expr) and self.expr[self.pos] in "+-":
            op = self.expr[self.pos]
            self.pos += 1
            right = self._parse_term()
            if op == "+":
                result += right
            else:
                result -= right
        return result

    def _parse_term(self):
        result = self._parse_factor()
        while self.pos < len(self.expr) and self.expr[self.pos] in "*/":
            op = self.expr[self.pos]
            self.pos += 1
            right = self._parse_factor()
            if op == "*":
                result *= right
            else:
                if right == 0:
                    raise ZeroDivisionError("Division by zero")
                result /= right
        return result

    def _parse_factor(self):
        if self.pos < len(self.expr) and self.expr[self.pos] == "(":
            self.pos += 1
            result = self._parse_expression()
            if self.pos < len(self.expr) and self.expr[self.pos] == ")":
                self.pos += 1
            else:
                raise ValueError("Missing closing parenthesis")
            return result

        # Parse number (including negative and decimal)
        start = self.pos
        if self.pos < len(self.expr) and self.expr[self.pos] == "-":
            self.pos += 1
        while self.pos < len(self.expr) and (self.expr[self.pos].isdigit() or self.expr[self.pos] == "."):
            self.pos += 1

        if start == self.pos:
            raise ValueError(f"Expected number at position {self.pos}")

        return float(self.expr[start:self.pos])

# Demo
calc = ExpressionEvaluator()
tests = [
    ("2 + 3", 5.0),
    ("10 - 4 * 2", 2.0),
    ("(2 + 3) * 4", 20.0),
    ("100 / (5 * 2)", 10.0),
    ("3 + 4 * 2 / (1 - 5)", 1.0),
]

for expr, expected in tests:
    result = calc.evaluate(expr)
    status = "PASS" if abs(result - expected) < 0.001 else "FAIL"
    print(f"{status}: {expr} = {result} (expected {expected})")

print("Calculator with operator precedence and parentheses working")
